/* ------------------------------------------------------------------ */
/* Phase state machine                                                */
/* ------------------------------------------------------------------ */

const PHASES = {
  INTRO: "INTRO",
  SEAWEED_RESCUE: "SEAWEED_RESCUE",
  FEEDING: "FEEDING",
  CELEBRATION: "CELEBRATION",
  TREASURE_CHEST: "TREASURE_CHEST",
  NEXT_RESCUE: "NEXT_RESCUE",
};

/** The default transition graph: what phase follows each phase.
 *  To insert a new activity (e.g. BUBBLE_POP) between two existing phases,
 *  just repoint the two edges around it - no other code needs to change. */
const PHASE_TRANSITIONS = {
  [PHASES.INTRO]: PHASES.SEAWEED_RESCUE,
  [PHASES.SEAWEED_RESCUE]: PHASES.FEEDING,
  [PHASES.FEEDING]: PHASES.CELEBRATION,
  [PHASES.CELEBRATION]: PHASES.TREASURE_CHEST,
  [PHASES.TREASURE_CHEST]: PHASES.NEXT_RESCUE,
  [PHASES.NEXT_RESCUE]: PHASES.SEAWEED_RESCUE,
};

