const DOLPHIN_BABY_IMG = "data:image/png;base64,"; // asset: dolphin-baby
// asset: sfx-nom (see asset-manifest.json -> categories.sounds)
function playNomSound() {
  try {
    const AudioCtx = window.AudioContext || window.webkitAudioContext;
    if (!AudioCtx) return;
    const ctx = new AudioCtx();
    const now = ctx.currentTime;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = "sine";
    osc.frequency.setValueAtTime(320, now);
    osc.frequency.exponentialRampToValueAtTime(560, now + 0.09);
    osc.frequency.exponentialRampToValueAtTime(210, now + 0.2);
    gain.gain.setValueAtTime(0.0001, now);
    gain.gain.exponentialRampToValueAtTime(0.35, now + 0.03);
    gain.gain.exponentialRampToValueAtTime(0.0001, now + 0.24);
    osc.connect(gain);
    gain.connect(ctx.destination);
    osc.start(now);
    osc.stop(now + 0.26);
    osc.onended = () => ctx.close();
  } catch (e) {
    // Audio isn't available in this environment - never let sound block the game.
  }
}

// asset: sfx-gem-chime (see asset-manifest.json -> categories.sounds)
function playChimeSound() {
  try {
    const AudioCtx = window.AudioContext || window.webkitAudioContext;
    if (!AudioCtx) return;
    const ctx = new AudioCtx();
    const now = ctx.currentTime;
    const freqs = [880, 1175, 1568];
    freqs.forEach((f, i) => {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = "sine";
      const t0 = now + i * 0.06;
      osc.frequency.setValueAtTime(f, t0);
      gain.gain.setValueAtTime(0.0001, t0);
      gain.gain.exponentialRampToValueAtTime(0.28, t0 + 0.02);
      gain.gain.exponentialRampToValueAtTime(0.0001, t0 + 0.35);
      osc.connect(gain);
      gain.connect(ctx.destination);
      osc.start(t0);
      osc.stop(t0 + 0.38);
    });
    setTimeout(() => ctx.close(), 500);
  } catch (e) {
    // Audio isn't available in this environment - never let sound block the game.
  }
}

function easeOutCubic(t) {
  return 1 - Math.pow(1 - t, 3);
}
function lerp(a, b, t) {
  return a + (b - a) * t;
}
function orbitPoint(frac) {
  const angle = Math.PI + frac * Math.PI * 2 * 1.4;
  return {
    x: ORBIT_CENTER.x + ORBIT_RADIUS * Math.cos(angle),
    y: ORBIT_CENTER.y + ORBIT_RADIUS * 0.55 * Math.sin(angle),
  };
}
function computeBabyPos(t) {
  if (t < ENTER_MS) {
    const e = easeOutCubic(t / ENTER_MS);
    const target = orbitPoint(0);
    return { x: lerp(BABY_START.x, target.x, e), y: lerp(BABY_START.y, target.y, e) };
  }
  if (t < ENTER_MS + ORBIT_MS) {
    return orbitPoint((t - ENTER_MS) / ORBIT_MS);
  }
  const e = easeOutCubic(Math.min(1, (t - ENTER_MS - ORBIT_MS) / SETTLE_MS));
  const start = orbitPoint(1);
  return { x: lerp(start.x, BABY_FINAL.x, e), y: lerp(start.y, BABY_FINAL.y, e) };
}

