/** The dolphin, reusable at any scale (adult or baby) with a swappable animation class.
 *  Pass src to use a different image asset (e.g. DOLPHIN_BABY_IMG); defaults to the adult. */
function Dolphin({ scale = 1, animClass = "bob", animKey = 0, src = DOLPHIN_IMG }) {
  const w = 280 * scale;
  const h = 141 * scale;
  const x = -160 * scale;
  const y = -80 * scale;
  return (
    <image key={animKey} className={`dolphin-group ${animClass}`} href={src} x={x} y={y} width={w} height={h} preserveAspectRatio="xMidYMid meet" />
  );
}

/** asset: fish-generic (see asset-manifest.json -> categories.fish)
 *  A large, colorful, draggable fish. Position/drag state is owned by the parent phase. */
function Fish({ fish, onPointerDown, onPointerMove, onPointerUp }) {
  const style = {
    left: `${fish.xPct}%`,
    top: `${fish.yPct}%`,
    transform: `translate(-50%,-50%) scaleX(${fish.dir}) ${fish.swallowing ? "scale(0.15)" : "scale(1)"}`,
    transition: fish.swallowing
      ? "left 0.42s ease-in, top 0.42s ease-in, transform 0.42s ease-in"
      : fish.dragging
      ? "none"
      : "transform 0.3s ease",
  };
  return (
    <div
      className={`fish-wrap ${fish.dragging ? "dragging" : ""}`}
      style={style}
      onPointerDown={onPointerDown}
      onPointerMove={onPointerMove}
      onPointerUp={onPointerUp}
      onPointerCancel={onPointerUp}
    >
      <div className={fish.dragging ? "" : "fish-bob"}>
        <svg viewBox="0 0 140 90" className="fish-svg">
          <path d="M18,45 L-15,18 L-15,72 Z" fill={fish.color.body} stroke="#16324A" strokeWidth="4" strokeLinejoin="round" />
          <ellipse cx="70" cy="45" rx="55" ry="32" fill={fish.color.body} stroke="#16324A" strokeWidth="4" />
          <path d="M52,32 Q70,22 92,30" fill="none" stroke={fish.color.belly} strokeWidth="7" strokeLinecap="round" opacity="0.9" />
          <circle cx="103" cy="36" r="9" fill="#fff" stroke="#16324A" strokeWidth="2.5" />
          <circle cx="105" cy="36" r="4.5" fill="#16324A" />
        </svg>
      </div>
    </div>
  );
}

